import{_ as t,c as o,o as a,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"License: BSL Terms and Usage | Plannotator","description":"Learn Plannotator's Business Source License 1.1 terms, usage restrictions, allowed use cases, prohibited services, and 2030 Apache 2.0 conversion timeline.","frontmatter":{"title":"License: BSL Terms and Usage | Plannotator","sidebarTitle":"License","subtitle":"License: BSL Terms and Usage | Plannotator","description":"Learn Plannotator's Business Source License 1.1 terms, usage restrictions, allowed use cases, prohibited services, and 2030 Apache 2.0 conversion timeline.","tags":["License","BSL-1.1","Commercial Use"],"prerequisite":[],"order":3},"headers":[],"relativePath":"backnotprop/plannotator/appendix/license/index.md","filePath":"backnotprop/plannotator/appendix/license/index.md"}`),r={name:"backnotprop/plannotator/appendix/license/index.md"};function i(s,e,l,c,d,p){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="plannotator-license-guide" tabindex="-1">Plannotator License Guide <a class="header-anchor" href="#plannotator-license-guide" aria-label="Permalink to &quot;Plannotator License Guide&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand the license type and core terms used by Plannotator</li><li>Identify which use cases are allowed and which are restricted</li><li>Know the license change timeline</li><li>Learn how to obtain commercial licensing or contact the licensor</li></ul><h2 id="what-you-need-to-know-now" tabindex="-1">What You Need to Know Now <a class="header-anchor" href="#what-you-need-to-know-now" aria-label="Permalink to &quot;What You Need to Know Now&quot;">​</a></h2><p>Plannotator uses the <strong>Business Source License 1.1 (BSL)</strong> as its open source license. This is a special license designed to protect commercial value while eventually making the project fully open source.</p><h2 id="core-terms" tabindex="-1">Core Terms <a class="header-anchor" href="#core-terms" aria-label="Permalink to &quot;Core Terms&quot;">​</a></h2><h3 id="license-type" tabindex="-1">License Type <a class="header-anchor" href="#license-type" aria-label="Permalink to &quot;License Type&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Content</th></tr></thead><tbody><tr><td><strong>License Name</strong></td><td>Business Source License 1.1 (BSL)</td></tr><tr><td><strong>Copyright Holder</strong></td><td>backnotprop (2025)</td></tr><tr><td><strong>Licensed Project</strong></td><td>plannotator</td></tr><tr><td><strong>Change Date</strong></td><td>2030-01-01</td></tr><tr><td><strong>License After Change</strong></td><td>Apache License, Version 2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">What is BSL?</p><p>Business Source License is a special license developed by MariaDB. It restricts certain commercial uses in the short term, but promises to convert the software to a fully open source license (like Apache 2.0) after a specific date. This model allows open source projects to obtain sustainable revenue during commercialization while ensuring long-term openness to the community.</p></div><h3 id="allowed-usage" tabindex="-1">Allowed Usage <a class="header-anchor" href="#allowed-usage" aria-label="Permalink to &quot;Allowed Usage&quot;">​</a></h3><p>According to BSL 1.1 terms, you may:</p><ul><li><p>✅ <strong>Copy, modify, and create derivative works</strong></p><ul><li>You can perform secondary development based on Plannotator</li><li>You can modify source code to fit your needs</li></ul></li><li><p>✅ <strong>Redistribute</strong></p><ul><li>You can distribute original or modified versions</li><li>Must retain original license notices</li></ul></li><li><p>✅ <strong>Non-production use</strong></p><ul><li>Internal development, testing, and evaluation</li><li>Personal learning and research</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">Broad Internal Use for Individuals and Companies</p><p>BSL&#39;s definition of &quot;non-production use&quot; is broad, covering various scenarios for individuals and companies internally. You and your team members (including independent contractors) can freely use Plannotator for development, testing, and deployment.</p></div><h3 id="usage-restrictions-important" tabindex="-1">Usage Restrictions (Important!) <a class="header-anchor" href="#usage-restrictions-important" aria-label="Permalink to &quot;Usage Restrictions (Important!)&quot;">​</a></h3><p><strong>Core Restriction</strong>: Plannotator may NOT be used for <strong>Planning, Context, or Approval Services</strong>.</p><h4 id="what-is-planning-context-or-approval-service" tabindex="-1">What is &quot;Planning, Context, or Approval Service&quot;? <a class="header-anchor" href="#what-is-planning-context-or-approval-service" aria-label="Permalink to &quot;What is &quot;Planning, Context, or Approval Service&quot;?&quot;">​</a></h4><p>Any commercial product that allows <strong>third parties</strong> (other than employees and independent contractors) to access Plannotator functionality through direct or indirect operations belongs to restricted services. Specifically including but not limited to:</p><ul><li><p><strong>Cloud Service Providers</strong></p><ul><li>SaaS platforms providing Plannotator functionality as part of their services</li><li>Hosting service providers providing Plannotator to customers or subscribers</li></ul></li><li><p><strong>Infrastructure Services</strong></p><ul><li>Data center service providers</li><li>Cloud computing platform providers</li></ul></li><li><p><strong>Third Parties Offering Similar Services</strong></p><ul><li>Any services provided by the above entities and their affiliates</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Commercial Use Warning</p><p>If you plan to use Plannotator as part of a commercial service provided to third parties, you must obtain a commercial license in advance. Violating this clause will automatically terminate your rights to use current and all future versions of Plannotator.</p></div><h2 id="license-change-timeline" tabindex="-1">License Change Timeline <a class="header-anchor" href="#license-change-timeline" aria-label="Permalink to &quot;License Change Timeline&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Time Node</th><th>License Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Current - 2030-01-01</strong></td><td>BSL 1.1</td><td>Restricted open source license</td></tr><tr><td><strong>From 2030-01-01</strong></td><td>Apache 2.0</td><td>Fully open source, no commercial restrictions</td></tr></tbody></table><h3 id="what-happens-after-the-change" tabindex="-1">What Happens After the Change? <a class="header-anchor" href="#what-happens-after-the-change" aria-label="Permalink to &quot;What Happens After the Change?&quot;">​</a></h3><p>Starting January 1, 2030, Plannotator will automatically convert to <strong>Apache License 2.0</strong>. This means:</p><ul><li>✅ All commercial restrictions will be removed</li><li>✅ Can be freely used for any commercial purpose</li><li>✅ Can be integrated into any SaaS service</li><li>✅ Complies with permissive open source license standards</li></ul><h2 id="commercial-license" tabindex="-1">Commercial License <a class="header-anchor" href="#commercial-license" aria-label="Permalink to &quot;Commercial License&quot;">​</a></h2><p>If you need to use Plannotator without complying with BSL restrictions (e.g., for planning, context, or approval services), you can:</p><ol><li><p><strong>Purchase Commercial License</strong></p><ul><li>Purchase from backnotprop or its authorized resellers</li><li>Obtain usage rights not subject to BSL restrictions</li></ul></li><li><p><strong>Contact Licensor</strong></p><ul><li>Email: backnotprop</li><li>Explain your use case and requirements</li></ul></li></ol><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="can-i-use-plannotator-within-my-company" tabindex="-1">Can I use Plannotator within my company? <a class="header-anchor" href="#can-i-use-plannotator-within-my-company" aria-label="Permalink to &quot;Can I use Plannotator within my company?&quot;">​</a></h3><p><strong>Yes.</strong> BSL explicitly allows you and your employees, independent contractors to use Plannotator for internal development, testing, and deployment. Restrictions only apply to scenarios where you provide services to <strong>third parties</strong> (non-employees and contractors).</p><h3 id="can-i-develop-my-own-product-based-on-plannotator" tabindex="-1">Can I develop my own product based on Plannotator? <a class="header-anchor" href="#can-i-develop-my-own-product-based-on-plannotator" aria-label="Permalink to &quot;Can I develop my own product based on Plannotator?&quot;">​</a></h3><p><strong>Yes, with conditions.</strong> If your product is:</p><ul><li>Internal tool: ✅ Allowed</li><li>Personal project: ✅ Allowed</li><li>Open source project: ✅ Allowed (retain BSL license)</li><li>Commercial product: ❓ Need to assess whether it falls under &quot;Planning, Context, or Approval Service&quot;</li></ul><h3 id="my-company-is-a-saas-provider-can-we-use-it" tabindex="-1">My company is a SaaS provider, can we use it? <a class="header-anchor" href="#my-company-is-a-saas-provider-can-we-use-it" aria-label="Permalink to &quot;My company is a SaaS provider, can we use it?&quot;">​</a></h3><p><strong>Commercial license required.</strong> If your SaaS product provides Plannotator functionality to customers (even as a feature), this belongs to restricted commercial service and you must purchase a commercial license.</p><h3 id="can-i-use-plannotator-for-any-purpose-after-2030" tabindex="-1">Can I use Plannotator for any purpose after 2030? <a class="header-anchor" href="#can-i-use-plannotator-for-any-purpose-after-2030" aria-label="Permalink to &quot;Can I use Plannotator for any purpose after 2030?&quot;">​</a></h3><p><strong>Yes.</strong> From the change date onwards, Plannotator will use Apache 2.0 license, all commercial restrictions will be removed, and you can freely use it for any purpose.</p><h2 id="full-license-text" tabindex="-1">Full License Text <a class="header-anchor" href="#full-license-text" aria-label="Permalink to &quot;Full License Text&quot;">​</a></h2><p>For the complete Business Source License 1.1 text, please refer to the <code>LICENSE</code> file in the project root directory.</p><h2 id="contact-information" tabindex="-1">Contact Information <a class="header-anchor" href="#contact-information" aria-label="Permalink to &quot;Contact Information&quot;">​</a></h2><p>For commercial licensing or other questions, please contact:</p><ul><li><strong>Licensor</strong>: backnotprop</li><li><strong>Project Repository</strong>: <a href="https://github.com/backnotprop/plannotator" target="_blank" rel="noreferrer">backnotprop/plannotator</a></li></ul><h2 id="next-up" tabindex="-1">Next Up <a class="header-anchor" href="#next-up" aria-label="Permalink to &quot;Next Up&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll check <strong><a href="./../../changelog/release-notes/">Release Notes</a></strong>.</p><p>You&#39;ll see:</p><ul><li>Plannotator&#39;s version history</li><li>New features and improvements in each version</li><li>Important bug fixes</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>License notice</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/README.md#L100-L104" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>100-104</td></tr><tr><td>Full license text</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer"><code>LICENSE</code></a></td><td>1-115</td></tr></tbody></table><p><strong>Key Information</strong>:</p><ul><li>License type: Business Source License 1.1 (BSL)</li><li>Copyright holder: backnotprop (c) 2025</li><li>Change date: 2030-01-01</li><li>License after change: Apache License, Version 2.0</li><li>Main restriction: Not for planning, context, or approval services</li></ul></details>',47)])])}const m=t(r,[["render",i]]);export{h as __pageData,m as default};
